public class Search2DMatrix { public static boolean searchMatrix(int[][] matrix, int target) { int m = matrix.length, n = matrix[0].length; int left = 0, right = m * n - 1; while(left <= right) { int mid = left + (right - left) / 2; int element = matrix[mid / n][mid % n]; if(element == target) return true; else if(element < target) left = mid + 1; else right = mid - 1; } return false; } }